let qrCode=new QRCodeStyling({width:260,height:260,type:"svg",data:"https://example.com",margin:0,dotsOptions:{color:"#003a77",type:"dots"},cornersSquareOptions:{color:"#003a77",type:"extra-rounded"},cornersDotOptions:{color:"#003a77"},backgroundOptions:{color:"#ffffff"}});const qrCanvas=document.getElementById("qr-canvas"),inputText=document.getElementById("qr-text"),inputSize=document.getElementById("qr-size"),inputColor=document.getElementById("qr-color"),btnGenerate=document.getElementById("btn-generate"),btnDownload=document.getElementById("btn-download");qrCode.append(qrCanvas);function updateQR(){const n=inputText.value.trim()||"https://example.com",t=parseInt(inputSize.value,10)||260,e=inputColor.value||"#003a77";qrCode.update({data:n,width:t,height:t,dotsOptions:{color:e,type:"dots"},cornersSquareOptions:{color:e,type:"extra-rounded"},cornersDotOptions:{color:e}})}btnGenerate.addEventListener("click",updateQR),btnDownload.addEventListener("click",()=>{qrCode.download({name:"dotted-qr-gajabtools",extension:"png"})}),updateQR()